INSERT INTO `dashboard_settings` (`id`, `key`, `value`, `type`, `group`, `label`, `description`, `sort_order`, `is_public`, `created_at`, `updated_at`) VALUES
(1, 'login_2fa_enabled', '0', 'boolean', 'security', 'Turn on 2FA during the login process?', 'Controls whether manual dashboard logins must complete a 2FA email code challenge.', 10, 0, '2026-05-06 22:41:34', '2026-06-24 10:46:39'),
(2, 'login_2fa_send_to_account', '1', 'boolean', 'security', 'Send 2FA Login emails to the account logging in?', 'Controls whether the 2FA login code is emailed to the user account that is signing in.', 20, 0, '2026-05-06 22:41:34', '2026-06-24 10:46:39'),
(3, 'login_2fa_send_to_master', '1', 'boolean', 'security', 'Send 2FA Login email copies to the Master email account?', 'Controls whether a copy of each 2FA login code is emailed to the configured master email account.', 30, 0, '2026-05-06 22:41:34', '2026-06-24 10:46:39'),
(4, 'login_2fa_master_email', '', 'email', 'security', 'Master email account', 'Receives 2FA login email copies when master email copies are enabled.', 40, 0, '2026-05-06 22:41:34', '2026-06-24 10:46:39'),
(5, 'game_active_week', 'week_1', 'string', 'game', 'Active course security week', 'Controls which weekly security preset is currently active for the cyber game.', 100, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(6, 'game_active_intake_id', '1', 'integer', 'game', 'Active intake', 'Stores the current class/intake selected for game management.', 110, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(7, 'security_protect_admin_account', '0', 'boolean', 'game_security', 'Protect Admin account from edit, ban, or delete', 'Blocks game actions from changing protected system/Admin accounts.', 200, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(8, 'security_geo_lock_user_edits', '0', 'boolean', 'game_security', 'Require user edits to originate from Australia', 'Blocks user update actions when the requester IP geolocates outside Australia.', 210, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(9, 'security_block_banned_login', '0', 'boolean', 'game_security', 'Block banned users from login', 'Prevents accounts marked BANNED from signing in during the game.', 220, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(10, 'security_require_audit_reason', '0', 'boolean', 'game_security', 'Require audit reason for dangerous actions', 'Requires a reason when users are edited, banned, deleted, restored, or reset.', 230, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(11, 'security_log_protected_attempts', '0', 'boolean', 'game_security', 'Log protected-account attempts', 'Creates audit records when a protected account action is blocked.', 240, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(12, 'security_notify_protected_attempts', '0', 'boolean', 'game_security', 'Notify Admins and Protectors about protected-account attempts', 'Creates warning notifications for defenders when protected accounts are targeted.', 250, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(13, 'security_hide_protected_audits', '0', 'boolean', 'game_security', 'Hide protected security audits from normal users', 'Limits sensitive security audit entries to Admin and Protector roles.', 260, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(14, 'game_allow_non_admin_add_users', '1', 'boolean', 'game_vulnerabilities', 'Allow non-admin players to add users', 'Keeps the intentional early-game vulnerability where ordinary players can create users.', 300, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(15, 'game_allow_non_admin_choose_roles', '1', 'boolean', 'game_vulnerabilities', 'Allow non-admin players to choose new user roles', 'Allows created users to receive elevated roles as part of the game vulnerability.', 310, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(16, 'game_allow_oauth_role_selection', '1', 'boolean', 'game_vulnerabilities', 'Allow Google OAuth registration to choose roles', 'Extends the role-selection vulnerability to Google OAuth-created users.', 320, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(17, 'game_oauth_default_role_id', '2', 'integer', 'game_vulnerabilities', 'Google OAuth default role ID', 'Role ID assigned to new OAuth users when OAuth role selection is disabled.', 330, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(18, 'game_delete_cooldown_enabled', '0', 'boolean', 'game_elimination', 'Lock attacker after deleting a user', 'Temporarily prevents the deleting player from taking further dangerous actions.', 400, 0, '2026-05-14 08:19:31', '2026-06-24 10:46:39'),
(19, 'game_delete_cooldown_minutes', '5', 'integer', 'game_elimination', 'Delete cooldown minutes', 'Number of minutes a player is action-locked after deleting another player.', 410, 0, '2026-05-14 08:19:31', '2026-06-24 10:46:39'),
(20, 'game_allow_undelete', '0', 'boolean', 'game_elimination', 'Allow deleted users to be restored', 'Enables defender recovery for users marked DELETED.', 420, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(21, 'game_undelete_roles', 'Admin,Protector', 'csv', 'game_elimination', 'Roles allowed to undelete users', 'Comma-separated role names that may restore deleted users when undelete is enabled.', 430, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(22, 'game_last_man_standing_enabled', '1', 'boolean', 'game_elimination', 'Use last-man-standing win condition', 'Treats the last active eligible player as the game winner.', 440, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(23, 'game_auto_detect_winner', '0', 'boolean', 'game_elimination', 'Automatically detect winner', 'Detects a winner when one active eligible player remains in the intake.', 450, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(24, 'game_protector_spy_controls', '0', 'boolean', 'game_roles', 'Only Protectors can see, ban, or delete spies', 'Restricts spy visibility and spy elimination actions to Protector users.', 500, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(25, 'game_spy_audit_impersonation', '0', 'boolean', 'game_roles', 'Allow spies to appear as other users in audit screens', 'Allows spy actions to show a displayed actor that differs from the real actor.', 510, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31'),
(26, 'game_baseline_reset_enabled', '1', 'boolean', 'game_reset', 'Enable intake baseline reset', 'Allows an intake to be restored to a known baseline without restoring the whole users table.', 600, 0, '2026-05-14 08:19:31', '2026-05-14 08:19:31');
